import i18n from "i18next";
import { initReactI18next } from "react-i18next";
import LanguageDetector from "i18next-browser-languagedetector";

i18n
  .use(LanguageDetector) // بيكتشف لغة المتصفح تلقائياً
  .use(initReactI18next) // بيربطه مع React
  .init({
    resources: {
      en: {
        translation: {
          nav_home: "Home",
          nav_about: "About Us",
          nav_products: "Products",
          nav_biscuits: "Biscuits",
          nav_cake: "Cake",
          nav_contact: "Contact Us",
        },
      },
      ar: {
        translation: {
          nav_home: "الرئيسية",
          nav_about: "من نحن",
          nav_products: "منتجاتنا",
          nav_biscuits: "البسكويت",
          nav_cake: "الكيك",
          nav_contact: "تواصل معنا",
        },
      },
    },
    fallbackLng: "ar", // إذا ما عرف اللغة بيعرض عربي
    interpolation: {
      escapeValue: false,
    },
  });

export default i18n;
